1	export type Customer = {
2	  yearsWithMHPCO: number;
3	};
4	
5	export type Item = {
6	  type: string;
7	  material?: string;
8	  cursed?: boolean;
9	  enchantment?: number;
10	};
11	
12	export type QuoteStep = {
13	  op: "quote";
14	  items: Item[];
15	};
16	
17	export type Step = QuoteStep;
18	
19	export type Scenario = {
20	  customer: Customer;
21	  steps: Step[];
22	};
23	
24	export type QuoteResult = {
25	  premium: number;
26	};
27	
28	export type Result = QuoteResult;
29	
30	const PROCESSING_FEE = 5;
31	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
32	const CURSE_SURCHARGE_RATE = 0.5;
33	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
34	const HIGH_ENCHANTMENT_MINIMUM = 5;
35	const LOYALTY_DISCOUNT_RATE = 0.2;
36	const LOYALTY_MINIMUM_YEARS = 2;
37	
38	const BASE_PREMIUMS: Record<string, number> = {
39	  sword: 100,
40	  amulet: 60,
41	  staff: 80,
42	  potion: 40,
43	  rune: 25,
44	  moonstone: 25,
45	};
46	
47	const COMPONENT_BLOCK_SIZE = 3;
48	const COMPONENT_BLOCK_PREMIUM = 60;
49	
50	const countByType = (items: Item[]): Map<string, number> => {
51	  const counts = new Map<string, number>();
52	  for (const item of items) {
53	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
54	  }
55	  return counts;
56	};
57	
58	const groupBasePremium = (type: string, count: number): number =>
59	  count === COMPONENT_BLOCK_SIZE
60	    ? COMPONENT_BLOCK_PREMIUM
61	    : count * BASE_PREMIUMS[type];
62	
63	const computeBasePremium = (items: Item[]): number =>
64	  [...countByType(items)].reduce(
65	    (total, [type, count]) => total + groupBasePremium(type, count),
66	    0,
67	  );
68	
69	const sumBy = (items: Item[], amount: (item: Item) => number): number =>
70	  items.reduce((total, item) => total + amount(item), 0);
71	
72	const itemCurseSurcharge = (item: Item): number =>
73	  item.cursed ? BASE_PREMIUMS[item.type] * CURSE_SURCHARGE_RATE : 0;
74	
75	const itemHighEnchantmentSurcharge = (item: Item): number =>
76	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_MINIMUM
77	    ? BASE_PREMIUMS[item.type] * HIGH_ENCHANTMENT_SURCHARGE_RATE
78	    : 0;
79	
80	const computeLoyaltyDiscount = (
81	  customer: Customer,
82	  basePremium: number,
83	): number =>
84	  customer.yearsWithMHPCO >= LOYALTY_MINIMUM_YEARS
85	    ? basePremium * LOYALTY_DISCOUNT_RATE
86	    : 0;
87	
88	const quotePremium = (customer: Customer, items: Item[]): number => {
89	  const basePremium = computeBasePremium(items);
90	  const curseSurcharge = sumBy(items, itemCurseSurcharge);
91	  const highEnchantmentSurcharge = sumBy(items, itemHighEnchantmentSurcharge);
92	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
93	  const loyaltyDiscount = computeLoyaltyDiscount(customer, basePremium);
94	  const exactPremium =
95	    basePremium +
96	    curseSurcharge +
97	    highEnchantmentSurcharge +
98	    firstInsuranceSurcharge -
99	    loyaltyDiscount +
100	    PROCESSING_FEE;
101	  return Math.ceil(exactPremium);
102	};
103	
104	export const processScenario = (scenario: Scenario): { results: Result[] } => ({
105	  results: [
106	    { premium: quotePremium(scenario.customer, scenario.steps[0].items) },
107	  ],
108	});
